package org.elasticsearch.xpack.esql.qa.single_node;

import org.elasticsearch.xpack.esql.CsvSpecReader.CsvTestCase;
import org.elasticsearch.xpack.esql.qa.rest.generative.ForkTestUtils;

import java.io.IOException;

import static org.junit.Assume.assumeFalse;

/**
 * Abstract base for per-csv-spec-file test classes generated by the Gradle build.
 * Each generated subclass covers one csv-spec file and wraps every test case with
 * a {@code FORK} suffix, exercising the FORK command with the same expected results
 * as the original spec.
 */
public abstract class AbstractEsqlSpecForkIT extends AbstractEsqlSpecIT {

    protected AbstractEsqlSpecForkIT(
        String fileName,
        String groupName,
        String testName,
        Integer lineNumber,
        CsvTestCase testCase,
        String instructions
    ) {
        super(fileName, groupName, testName, lineNumber, testCase, instructions);
    }

    @Override
    protected void doTest() throws Throwable {
        // Dataset-backed specs are covered by the external-source suites; skip them here.
        assumeFalse("dataset-backed spec; covered by the external-source suites", testCase.datasetSources.isEmpty() == false);
        // We add a LIMIT in one of the branches to prevent filter pushdown from removing one of the branches.
        String query = testCase.query + " | FORK (WHERE true | LIMIT 300) (WHERE true) | LIMIT 300 | WHERE _fork == \"fork1\" | DROP _fork";
        doTest(query);
    }

    @Override
    protected void shouldSkipTest(String testName) throws IOException {
        super.shouldSkipTest(testName);
        ForkTestUtils.shouldSkipForkTest(testCase, adminClient());
    }
}
